export type Interval = {
  start: number;
  end: number;
};

export type CoalesceOptions = {
  mergeTouching?: boolean;
};

export function coalesceIntervals(intervals: readonly Interval[], options: CoalesceOptions = {}): Interval[] {
  const mergeTouching = options.mergeTouching ?? true;
  const normalized = intervals.map(normalizeInterval).sort((a, b) => a.start - b.start || a.end - b.end);
  const result: Interval[] = [];

  for (const interval of normalized) {
    const last = result.at(-1);
    if (!last) {
      result.push({ ...interval });
      continue;
    }
    const overlaps = mergeTouching ? interval.start <= last.end : interval.start < last.end;
    if (overlaps) {
      last.end = Math.max(last.end, interval.end);
    } else {
      result.push({ ...interval });
    }
  }

  return result;
}

function normalizeInterval(interval: Interval): Interval {
  assertFinite(interval.start, "start");
  assertFinite(interval.end, "end");
  return interval.start <= interval.end
    ? { start: interval.start, end: interval.end }
    : { start: interval.end, end: interval.start };
}

function assertFinite(value: number, label: string): void {
  if (!Number.isFinite(value)) throw new Error(`Interval ${label} must be finite`);
}

import { describe, expect, it } from "vitest";
import { coalesceIntervals } from "../src/intervals";

describe("coalesceIntervals", () => {
  it("merges overlaps deterministically", () => {
    expect(
      coalesceIntervals([
        { start: 5, end: 8 },
        { start: 1, end: 3 },
        { start: 2, end: 6 },
      ]),
    ).toEqual([{ start: 1, end: 8 }]);
  });

  it("can keep touching intervals separate", () => {
    expect(
      coalesceIntervals(
        [
          { start: 1, end: 2 },
          { start: 2, end: 3 },
        ],
        { mergeTouching: false },
      ),
    ).toEqual([
      { start: 1, end: 2 },
      { start: 2, end: 3 },
    ]);
  });

  it("normalizes reversed and negative ranges", () => {
    expect(
      coalesceIntervals([
        { start: 4, end: -1 },
        { start: -3, end: -2 },
      ]),
    ).toEqual([{ start: -3, end: 4 }]);
  });

  it("rejects invalid endpoints", () => {
    expect(() => coalesceIntervals([{ start: 1, end: Number.NaN }])).toThrow(/finite/);
  });
});

